// Aggregate OCR text from all pages
let aggregatedText = '';
let pageTexts = [];

for (const item of $input.all()) {
  try {
    const responses = item.json.responses[0].responses;

    for (const page of responses) {
      const pageNumber = (page.context && page.context.pageNumber) || pageTexts.length + 1;

      const pageText = page.fullTextAnnotation.text;

      pageTexts.push({
        pageNumber: pageNumber,
        text: pageText
      });

      aggregatedText += page.fullTextAnnotation.text + '\n\n';
    }
  } catch (error) {
    return [{
      json: {
        error: error.message,
        aggregatedText: '',
        debug: JSON.stringify(item.json, null, 2)
      }
    }];
  }
}

return [{
  json: {
    aggregatedText: aggregatedText.trim(),
    totalPages: pageTexts.length,
    pages: pageTexts
  }
}];

const o = $input.first().json.output ?? $input.first().json;

const name = `${o.establecimiento ?? ''} ${o.tienda ?? ''} ${o.retailer ?? ''}`.toUpperCase();

let categoria = o.categoria;

if (name.includes('ALKOSTO')) categoria = 'MERCADO';
// aquí puedes sumar más reglas:
// if (name.includes('EXITO')) categoria = 'MERCADO';
// if (name.includes('RAPPI')) categoria = 'DOMICILIOS';

return [{
  json: {
    ...o,
    categoria
  }
}];

