const item = $input.first();
try {
  const resp = item.json.responses[0];
  const text = resp.fullTextAnnotation ? resp.fullTextAnnotation.text : '';
  return [{ json: { aggregatedText: text, totalPages: 1 } }];
} catch (error) {
  return [{ json: { error: error.message, aggregatedText: '' } }];
}

// Normalizar fecha a DD/MM/YYYY
function normalizeFecha(raw) {
  if (!raw) return '';
  const s = String(raw).trim();
  let d, m, y;
  // YYYY-MM-DD
  let match = s.match(/^(\d{4})-(\d{1,2})-(\d{1,2})/);
  if (match) { [, y, m, d] = match; }
  // DD/MM/YYYY o DD-MM-YYYY
  if (!match) { match = s.match(/^(\d{1,2})[\/-](\d{1,2})[\/-](\d{4})/); }
  if (match && !y) {
    // Ambiguo: asumimos D/M/Y si primer num <= 31 y segundo <= 12
    const a = parseInt(match[1]), b = parseInt(match[2]);
    if (a > 12) { d = match[1]; m = match[2]; y = match[3]; }
    else if (b > 12) { m = match[1]; d = match[2]; y = match[3]; }
    else { d = match[1]; m = match[2]; y = match[3]; } // default D/M/Y
  }
  // M/D/YYYY (US format from LLM)
  if (!y) return s;
  return y + '-' + String(m).padStart(2,'0') + '-' + String(d).padStart(2,'0');
}

const fields = $('Mapear Campos Email').item.json;
const tasa = $('Obtener Tasa USD (Email)').item.json.rates?.COP || 4200;
const moneda = ($('Extraer Datos Email (IA)').item.json.output.moneda || 'COP').toUpperCase();

// Parsear monto manejando formatos colombianos y estadounidenses
function parseMonto(value) {
  let raw = String(value).trim();
  // Strip currency symbols/prefixes first
  raw = raw.replace(/^(?:USD|COP|US\$|\$)\s*/i, '').trim();
  // Caso 1: coma decimal al final (13,99 o 1.234,50)
  if (/,\d{1,2}$/.test(raw)) {
    raw = raw.replace(/\./g, '').replace(',', '.');
  }
  // Caso 2: punto como separador de miles (56.000, 1.234.567)
  // Detectar: punto seguido de exactamente 3 dígitos (repetido)
  else if (/^[\d.]+(\d{3})$/.test(raw) && /\.\d{3}/.test(raw)) {
    raw = raw.replace(/\./g, '');
  }
  // Caso 3: comas como miles (1,000,000)
  else {
    raw = raw.replace(/,/g, '');
  }
  return parseFloat(raw.replace(/[^\d.]/g, '')) || 0;
}

let total = parseMonto(fields.total);

if (moneda === 'USD') {
  total = Math.round(total * tasa);
}

const totalFormatted = '$' + total.toLocaleString('es-CO');

return [{
  json: {
    ...fields,
    fecha: normalizeFecha(fields.fecha),
    total,
    total_formatted: totalFormatted,
    moneda_original: moneda,
    tasa_usd_cop: moneda === 'USD' ? tasa : null,
  }
}];

